            overflow: 'hidden'
          }}
        >
          <div
            style={{
              display: 'grid',
              gridTemplateColumns: '1.6fr 0.8fr 0.8fr 0.8fr',
              gap: 0,
              padding: '18px 24px',
              borderBottom: '1px solid rgba(17, 24, 39, 0.08)',
